

const sleep = (t) => new Promise((r) => setTimeout(r, t));

export function swiperInit() {
	function getSlidesPerGroup(slidesSizesGrid, visibleSlidesIndexes) {
		const totalSlide = slidesSizesGrid.length;
		const visibleSlide = visibleSlidesIndexes?.length ?? 1;

		let slidesPerGroup = visibleSlide;

		if (totalSlide <= visibleSlide) {
			slidesPerGroup = null;
		}
		return slidesPerGroup;
	}
	function triggerLozadNextSlideImage(swiper) {
		const nextSlide = swiper.slides[swiper.activeIndex + 1];
		if (nextSlide) {
			const nextImage = nextSlide.querySelectorAll("img");
			if (nextImage && typeof lazyLoader.triggerLoad === "function") {
				nextImage.forEach((img) => {
					lazyLoader.triggerLoad(img);
				});
			} else {
				throw new Error("Lozad is not defined");
			}
		}
	}
	function autoSetSlidesPerGroup(swiper) {
		if (!swiper.pagination.el) return;
		const { visibleSlidesIndexes, slidesSizesGrid } = swiper;
		const slidesPerGroup = getSlidesPerGroup(
			slidesSizesGrid,
			visibleSlidesIndexes
		);
		if (
			slidesPerGroup != null &&
			slidesPerGroup > 0 &&
			slidesPerGroup !== swiper.params.slidesPerGroup
		) {
			swiper.params.slidesPerGroup = slidesPerGroup;
			swiper.update();
		}
	}


	var partnerSwiper = new Swiper(".partner-swiper .swiper", {
		loop: true,
		speed: 2000,
		spaceBetween: 20,
		autoplay: {
			delay: 0,
			disableOnInteraction: false,
		},
		breakpoints: {
			320: {
				slidesPerView: 3,
			},
			768: {
				slidesPerView: 4,
			},
			1024: {
				slidesPerView: 6,
			},
			1200: {
				slidesPerView: 8,
			},

		},
	});



	var slideNumberVerticalSwiper = new Swiper(".slide-number-vertical .swiper", {
		loop: true,
		speed: 900,
		spaceBetween: 20,
		autoplay: {
			delay: 2000,
			disableOnInteraction: false,
		},
		direction: "vertical",
		breakpoints: {
			320: {
				slidesPerView: 1,
			},

		},
	});


	// 1. Initialize Swiper
	var primarySwiper = new Swiper(".primary-banner .swiper", {
		slidesPerView: 1,
		observer: true,
		observeParents: true,
		preventInteractionOnTransition: false,
		speed: 1205,
		autoplay: false,
		lazy: {
			loadPrevNext: true,
		},
		effect: "fade",
		fadeEffect: {
			crossFade: true,
		},
		loop: true,
		init: false,
		navigation: {
			nextEl: ".primary-banner .next",
			prevEl: ".primary-banner .prev",
		},
		pagination: {
			el: ".primary-banner .swiper-pagination",
			type: "bullets",
			clickable: true,
			renderBullet: function (index, className) {
				return `<span class="${className}" data-index="${index}"></span>`;
			},
		},
	});

	// 2. Global Variables
	let progressInterval = null;
	let timer = null;
	let isPaused = false; // NEW: Track manual pause state
	const slideTimeout = 4000;

	// 3. Progress Track Function
	function startProgressTrack() {
		if (progressInterval) clearInterval(progressInterval);
		if (isPaused) return; // Don't start animation if paused

		const progressTrack = document.querySelector(".primary-banner .progress-track");
		if (!progressTrack) return;

		const intervalStep = 20;
		// Get current width to allow resuming from same spot if desired, 
		// otherwise it defaults to 0 on new slides.
		let progress = parseFloat(progressTrack.style.width) || 0;

		progressInterval = setInterval(() => {
			if (!isPaused) {
				progress += (intervalStep / slideTimeout) * 100;
				if (progress >= 100) {
					clearInterval(progressInterval);
					progressTrack.style.width = "100%";
				} else {
					progressTrack.style.width = `${progress}%`;
				}
			}
		}, intervalStep);
	}

	function resetProgressTrack() {
		if (progressInterval) {
			clearInterval(progressInterval);
			progressInterval = null;
		}
		const progressTrack = document.querySelector(".primary-banner .progress-track");
		if (progressTrack) {
			progressTrack.style.width = "0%";
		}
	}

	// 4. Video & Timer Handling
	function handleVideoPlayback(slide) {
		if (timer) {
			clearTimeout(timer);
			timer = null;
		}

		// We only reset the track to 0% if we aren't in a paused state 
		// (this prevents the bar from vanishing when clicking pause)
		if (!isPaused) {
			resetProgressTrack();
		}

		const allVideos = document.querySelectorAll(".primary-banner-video");
		allVideos.forEach((video) => {
			video.pause();
		});

		const videoElement = slide.querySelector("video");
		if (videoElement) {
			if (!isPaused) {
				startProgressTrack();
				videoElement.play().catch((error) => {
					timer = setTimeout(() => {
						primarySwiper.slideNext();
					}, slideTimeout);
				});
			}

			videoElement.addEventListener("ended", function () {
				if (!isPaused) {
					if (primarySwiper.slides.length === 1) {
						videoElement.currentTime = 0;
						videoElement.play();
					} else {
						primarySwiper.slideNext();
					}
				}
			}, { once: true });

		} else {
			// Handle Image Slides
			if (!isPaused) {
				startProgressTrack();
				timer = setTimeout(() => {
					primarySwiper.slideNext();
				}, slideTimeout);
			}
		}
	}

	// 5. Swiper Event Listeners
	primarySwiper.on("slideChangeTransitionEnd", function () {
		const currentSlide = primarySwiper.slides[primarySwiper.activeIndex];
		handleVideoPlayback(currentSlide);
	});

	primarySwiper.on("slideChangeTransitionStart", function () {
		if (!isPaused) {
			resetProgressTrack();
		}
	});

	primarySwiper.on("init", function () {
		const currentSlide = primarySwiper.slides[primarySwiper.activeIndex];
		handleVideoPlayback(currentSlide);
	});

	// 6. Pause Button Logic (.pause-track)
	const pauseTrackBtn = document.querySelector(".pause-track");
	if (pauseTrackBtn) {
		pauseTrackBtn.addEventListener("click", function () {
			isPaused = !isPaused; // Toggle state

			const currentSlide = primarySwiper.slides[primarySwiper.activeIndex];
			const video = currentSlide.querySelector("video");

			if (isPaused) {
				// STOP
				this.classList.add("paused");
				if (progressInterval) clearInterval(progressInterval);
				if (timer) clearTimeout(timer);
				if (video) video.pause();
			} else {
				// RESUME
				this.classList.remove("paused");
				if (video) {
					video.play();
					startProgressTrack();
				} else {
					startProgressTrack();
					// Resume the remaining time (simplified as full timeout here)
					timer = setTimeout(() => {
						primarySwiper.slideNext();
					}, slideTimeout);
				}
			}
		});
	}

	// 7. Manual Video Click Handling
	const primaryBannerVideo = document.querySelectorAll(".primary-banner-video");
	primaryBannerVideo.forEach(function (videoElement) {
		videoElement.addEventListener("click", function (event) {
			if (this.paused) {
				this.play();
				this.parentNode.classList.remove("pause");
			} else {
				this.pause();
				this.parentNode.classList.add("pause");
			}
		});
	});

	// 8. Run Init
	primarySwiper.init();





	window.initSwiper = [];
	$(".init-swiper .swiper").each(function (index) {
		const $this = $(this);
		let isLoop = false;
		let time = $(this).attr("data-time") || 5000;
		let isTriggerLoadedNext = false;

		if ($this.hasClass("trigger-loaded-next")) {
			isTriggerLoadedNext = true;
		}
		// 1. Define a default pagination type
		let paginationType = "bullets";

		// 2. Add your new check
		if ($this.hasClass("fraction")) {
			paginationType = "fraction";
		} else if ($this.hasClass("progress")) {
			paginationType = "progressbar";
		}
		$this.addClass("swiper-init-" + index);
		$this.parents(".init-swiper").find(".prev").addClass("prev-nav-" + index);
		$this.parents(".init-swiper").find(".next").addClass("next-nav-" + index);
		$this
			.parents(".init-swiper")
			.find(".swiper-pagination")
			.addClass("pagination-inst-" + index);

		const options = {
			observer: true,
			observeParents: true,
			rewind: true,
			speed: 1205,
			watchSlidesProgress: true,
			lazy: {
				loadPrevNext: true,
			},
			loop: isLoop,
			autoplay: {
				delay: time,
				pauseOnMouseEnter: true,
			},
			slidesPerView: "auto",
			navigation: {
				nextEl: ".next-nav-" + index,
				prevEl: ".prev-nav-" + index,
			},
			pagination: {
				el: ".pagination-inst-" + index,
				type: paginationType, // 3. Use the dynamic type here
				clickable: true,
				dynamicMainBullets: 1,
			},
			on: {
				beforeInit: function () {
					window.initSwiper.push(this);
				},
				init: function (swiper) {
					if (isLoop) {
						lozadInit();
						$(this.el)
							.find(".swiper-slide-duplicate a[data-fancybox]")
							.each(function () {
								$(this).removeAttr("data-fancybox");
							});
					}
					if (isTriggerLoadedNext) {
						triggerLozadNextSlideImage(this);
					}
				},
				slideChange: function () {
					if ($this.hasClass("slide-has-video")) {
						$this.find("video")[0].pause();
						$this.find(".swiper-slide").removeClass("play-video");
						$this.find(".play-btn").removeClass("active");
					}

					if (isTriggerLoadedNext) {
						triggerLozadNextSlideImage(this);
					}
				},
				resize: function (swiper) {
					const totalSlidesWidth = swiper.slidesSizesGrid.reduce(
						(acc, curr) => acc + curr,
						0
					);
					swiper.el.classList.toggle(
						"center-slide-active",
						totalSlidesWidth < swiper.size
					);
					autoSetSlidesPerGroup(this);
				},
			},
		};

		// ✅ Add or remove centeredSlides based on .is-center-slide
		if ($this.hasClass("is-center-slide")) {
			options.centeredSlides = true;
		} else {
			delete options.centeredSlides;
		}

		// ✅ Add initialSlide support (from custom attribute)
		const initialSlide = parseInt($this.attr("data-initial"), 10);
		if (!isNaN(initialSlide)) {
			options.initialSlide = initialSlide;
		}

		if (time == 0) {
			options.autoplay = {
				delay: 0,
				disableOnInteraction: true,
				pauseOnMouseEnter: false,
			};
			options.loop = true;
			options.speed = 1800;
			delete options.navigation;
		}

		var swiper_slide_auto = new Swiper(".swiper-init-" + index, {
			...options,
		});
	});



	var gridSwiper = new Swiper(".branding-grid-swiper .swiper", {
		preventInteractionOnTransition: true,
		observer: true,
		observeParents: true,
		rewind: true,
		speed: 1205,
		autoplay: {
			delay: 4000,
			pauseOnMouseEnter: true,
		},
		lazy: {
			loadPrevNext: true,
		},
		spaceBetween: 15,
		observeParents: true,
		simulateTouch: false,
		breakpoints: {
			320: {
				slidesPerView: 2,
				grid: {
					rows: 2,
					fill: "row",
				},
			},
			420: {
				slidesPerView: 3,
				grid: {
					rows: 2,
					fill: "row",
				},
			},

			768: {
				slidesPerView: 4,
				grid: {
					rows: 2,
					fill: "row",
				},
			},
			1024: {
				slidesPerView: 2,
				grid: {
					rows: 2,
					fill: "row",
				},
			},
			1400: {
				slidesPerView: 3,
				spaceBetween: 20,
				grid: {
					rows: 2,
					fill: "row",
				},
			},
		},
		navigation: {
			nextEl: ".partner-grid-swiper .next",
			prevEl: ".partner-grid-swiper .prev",
		},
	});



	// ---------- THUMB SLIDER ----------
	var homeThumb = new Swiper(".home-thumb .swiper", {
		spaceBetween: 0,
		watchSlidesProgress: true,
		slideToClickedSlide: true,
		speed: 1205,
		autoplay: false,
		lazy: {
			loadPrevNext: true,
		},
		breakpoints: {
			200: {
				slidesPerView: 1,
			},
			476: {
				slidesPerView: 1,
			},
			768: {
				slidesPerView: 2,
			},
			1024: {
				slidesPerView: 3,
			},
			1280: {
				slidesPerView: 4,
			},
		},
	});

	window.homeThumb = homeThumb;


	// ---------- MAIN SLIDER ----------
	var homeMain = new Swiper(".home-main .swiper", {
		spaceBetween: 10,
		centeredSlides: true,
		speed: 1205,
		rewind: true,
		effect: "fade",
		fadeEffect: {
			crossFade: true,
		},
		autoplay: {
			delay: 3000,
			pauseOnMouseEnter: false,
			disableOnInteraction: false,
		},
		lazy: {
			loadPrevNext: true,
		},
		thumbs: {
			swiper: homeThumb,
		},
	});

	window.homeMain = homeMain;


	// ---------- HOVER THUMB → CHANGE MAIN ----------
	function bindThumbHover() {
		document
			.querySelectorAll(".home-thumb .swiper-slide")
			.forEach((slide, index) => {

				slide.addEventListener("mouseenter", () => {
					homeMain.autoplay.stop();
					homeMain.slideTo(index);
				});

				slide.addEventListener("mouseleave", () => {
					homeMain.autoplay.start();
				});
			});
	}

	// bind after Swiper is ready
	homeThumb.on("init", bindThumbHover);
	bindThumbHover();


	// ---------- KEEP THUMB IN SYNC WHEN MAIN CHANGES ----------
	homeMain.on("slideChange", () => {
		homeThumb.slideTo(homeMain.activeIndex);
	});



}