export function basicTask() {
	const backTop = document.querySelector(".back-to-top");
	const counterItem = document.querySelectorAll(".counter");
	const setBackground = document.querySelectorAll("[setBackground]");
	const menuToggle = document.querySelector(".site-menu-toggle");
	const closeMenu = document.querySelector(".close-menu");
	const searchToggle = document.querySelector(".search-toggle");
	const bodyWrap = document.querySelector("body");
	const menuMobile = document.querySelector(".mobile-nav-wrap");
	const searchWrap = document.querySelector(".searchbox");
	const hamburger = document.querySelector(".hamburger");


	try {


		const bgContainer = $(".home-services .bg-placeholder");
		$(".home-services .item-bg").each(function () {
			$(this).on("mouseenter", function () {
				let srcImage = $(this).attr("data-src");
				bgContainer[0].style.setProperty("--bg-hover", `url(${srcImage})`);
				bgContainer.css("--bg-hover", `url(${srcImage})`);
			});
		});

		bgContainer.on("mouseenter", function () {
			$(this).addClass("active");
			console.log(123);
		});
		bgContainer.on("mouseleave", function () {
			$(this).removeClass("active");
			console.log(234);
		});



		var lang = document.documentElement.lang || "en-US";
		var dateInputs = document.querySelectorAll(".wrap-form .custom-datepicker input");

		var placeholderText = lang.toLowerCase().startsWith("vi") ? "Ngày dự kiến" : "Expected date";

		dateInputs.forEach(function (input) {
			// 1. Initial State
			input.type = "date";

			// If there is no value initially, set the placeholder
			if (!input.value) {
				input.setAttribute("placeholder", placeholderText);
				input.classList.remove("has-value");
			} else {
				input.setAttribute("placeholder", ""); // Clear it if value exists
				input.classList.add("has-value");
			}

			// 2. Open calendar on focus
			input.addEventListener("focus", function () {
				try {
					this.showPicker();
				} catch (e) { }
			});

			// 3. THE FIX: Toggle the placeholder attribute itself
			input.addEventListener("change", function () {
				if (this.value) {
					this.classList.add("has-value");
					this.setAttribute("placeholder", ""); // Wipe the text out
				} else {
					this.classList.remove("has-value");
					this.setAttribute("placeholder", placeholderText); // Bring it back
				}
			});

			// 4. Handle blur (checking both blur and input for iOS stability)
			input.addEventListener("blur", function () {
				var self = this;
				setTimeout(function () {
					if (!self.value) {
						self.classList.remove("has-value");
						self.setAttribute("placeholder", placeholderText);
					} else {
						self.setAttribute("placeholder", "");
					}
				}, 100);
			});
		});
	} catch (error) {
		console.error("Datepicker placeholder error:", error);
	}

	try {
		/**
		 * Handle the hover state for the flower container
		 */
		const flowerContainer = document.querySelector('.container-flower');

		if (flowerContainer) {
			flowerContainer.addEventListener('mouseenter', () => {
				// Select all droplet elements inside the container
				const droplets = flowerContainer.querySelectorAll('.droplet-wrap');

				droplets.forEach(droplet => {
					// Remove the .is-first class if it exists
					if (droplet.classList.contains('is-first')) {
						droplet.classList.remove('is-first');
					}
				});

				console.log('User hovered: Removed .is-first from all droplets.');
			});
		}
		$(".tooltip").tooltipster({
			contentCloning: true,
			maxWidth: 320,
			minWidth: 280,
			interactive: true,
			trigger:
				/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
					navigator.userAgent
				)
					? "click"
					: "hover",
		});
	} catch (error) {

	}

	$(".filter-toggle").on("click", function () {
		$(".mobile-filter-wrap").toggleClass("is-open");
	});
	$(".close-filter").on("click", function () {
		$(".mobile-filter-wrap").removeClass("is-open");
	});

	$(".tab-select select").on("change", function () {
		var tab = $(this).val();
		var section = $(this).parents("section");
		// Target elements with both the ID and the specific class
		section.find(".tab-select-item").removeClass("is-active");
		section.find(".tab-select-item#" + tab).addClass("is-active");
	});
	$("body").on("click", ".dealer-network .item", function (e) {
		let map = $(this).attr("data-map");
		$(".dealer-network .item").removeClass("is-active");
		$(this).addClass("is-active");
		$(".map-wrap iframe").attr("src", map);
	});



	//Toggle Nav
	$(".drop-menu .title em").on("click", function () {
		if ($(this).parents(".drop-menu").hasClass("active")) {
			$(".drop-menu .nav-menu").slideUp();
			$(".drop-menu").removeClass("active");
		} else {
			$(".drop-menu .nav-menu").slideUp();
			$(".drop-menu").removeClass("active");
			$(this).parent().next().slideDown();
			$(this).parents(".drop-menu").addClass("active");
		}
	});
	$(".side-nav-mobile .title-nav").on("click", function () {
		$(".side-nav").slideToggle();
		$(this).parent().toggleClass('is-active');
	});



	$(".toggle-wrap-hover").each(function (index, element) {
		let $wrap = $(this);
		let enterTimer; // leaveTimer is no longer needed

		// --- Initialization: Show the first item on page load ---
		$wrap.find(".toggle-item-hover").first().each(function () {
			let $firstItem = $(this);
			$firstItem.addClass("is-toggle");
			$firstItem.find(".article").css('display', 'block');
		});

		// Event Handlers
		$wrap.find(".toggle-item-hover")
			.on("mouseenter", function () {
				let $item = $(this);

				// If we hover over a new item, trigger the change
				enterTimer = setTimeout(function () {
					if (!$item.hasClass("is-toggle")) {
						// 1. Hide the previous active article
						$wrap.find(".toggle-item-hover.is-toggle")
							.removeClass("is-toggle")
							.find(".article")
							.slideUp(200);

						// 2. Show the new one
						$item.addClass("is-toggle");
						$item.find(".article").slideDown(200);
					}
				}, 150);
			})
			.on("mouseleave", function () {
				// Stop the timer if the user glides over an item too fast
				clearTimeout(enterTimer);

				// NOTE: We no longer slideUp here. 
				// This keeps the last item active when leaving the parent div.
			});
	});

	let hoverTimer; // debounce timer

	$(".tab-nav-hover li").on("mouseenter", function (e) {
		clearTimeout(hoverTimer); // clear previous timer
		const $link = $(this);
		hoverTimer = setTimeout(function () {
			const $nav = $link.parents(".tab-nav-hover");
			const $section = $link.parents("section");

			// Update active nav link
			$nav.find("li").removeClass("is-active");
			$link.parents("li").addClass("is-active");

			const tab = $link.attr("data-type");
			const $items = $section.find(".tab-item-hover");

			// Hide all tabs
			$items.stop(true, true).hide().removeClass("is-active");

			// Fade in selected tab
			$section.find("#" + tab).stop(true, true).fadeIn(300).addClass("is-active");
		}, 150); // delay in ms (adjust for sensitivity)
	});

	$(".tab-nav-hover a.title").on("mouseleave", function () {
		clearTimeout(hoverTimer);
	});


	//Basic Toggle Function
	menuToggle.addEventListener("click", (e) => {
		e.preventDefault();
		menuMobile.classList.toggle("is-open");
		hamburger.classList.toggle("is-active");
		bodyWrap.classList.toggle("overlay-bg");
	});
	closeMenu.addEventListener("click", () => {
		menuMobile.classList.remove("is-open");
		hamburger.classList.remove("is-active");
		bodyWrap.classList.remove("overlay-bg");
	});

	// Search Toggle
	searchToggle.addEventListener("click", () => {
		searchWrap.classList.toggle("is-open");
		bodyWrap.classList.toggle("overlay-bg");
	});

	//back to top
	backTop.addEventListener("click", (event) => {
		event.preventDefault();
		$("html, body").animate({ scrollTop: 0 }, "300");
	});
	$(".menu-item > a").wrap("<div class='title'></div>");
	$(".menu-item-has-children >.title").append("<div class='icon'></div>");
	//Tab function

	$(".mobile-menu-nav .menu-item-has-children .title .icon").on("click", function () {
		$(this).parent().next().slideToggle();
		$(this).parent().toggleClass('is-active');
	});
	//Tab function
	$(".rolling-text").each(function () {
		const $element = $(this);
		const innerText = $element.text().trim();
		$element.empty();

		const createTextContainer = () =>
			$("<div>")
				.addClass("block")
				.append(
					[...innerText].map((letter) =>
						$("<span>")
							.addClass("letter")
							.text(letter.trim() === "" ? "\xa0" : letter)
					)
				);

		$element.append(createTextContainer()).append(createTextContainer());
	});
	$(".toggle-wrap").each(function (index, element) {
		let $this = $(this);
		$this.addClass("toggle-instance-" + index);
		$(".toggle-instance-" + index + " .toggle-item").click(function () {
			if ($(this).hasClass("is-toggle")) {

				$(this).find(".article").slideUp();
				$(this).removeClass("is-toggle");
			} else {
				$(".toggle-item").find(".article").slideUp();
				$(".toggle-item").removeClass("is-toggle");
				$(this).find(".article").slideDown();
				$(this).addClass("is-toggle");
			}
		});
	});

	if ($(".sticky-nav").length) {
		$(".sticky-nav").scrollToFixed({
			zIndex: 99,
			marginTop: 100,
			limit: function () {
				return (
					$("footer").offset().top -
					$(".sticky-nav").outerHeight() -
					$("header").outerHeight()
				);
			},
			fixed: function () {
				// sticky element is active
				$(this).addClass("is-sticky").removeClass("at-limit");
			},
			postLimit: function () {
				// reached the limit
				$(this).addClass("at-limit").removeClass("is-sticky");
			},
			postFixed: function () {
				// no longer fixed (scrolling back up)
				$(this).removeClass("is-sticky at-limit");
			}
		});
	}

	$(window)
		.scroll(function () {
			var scrollDistance = $(window).scrollTop();
			// Assign active class to nav links while scolling
			$(".scroll-section-wrap .anchor-section-id").each(function (i) {
				if (
					$(this).position().top -
					$(".sticky-nav").outerHeight() -
					80 -
					1 <=
					scrollDistance
				) {
					$(".sticky-nav li.active").removeClass("active");
					$(".sticky-nav li").eq(i).addClass("active");
				}
			});
		})
		.scroll();
	$(".sticky-nav  a").on("click", function (event) {
		if (this.hash !== "") {
			let offset =
				$("header").outerHeight() + $(".sticky-nav").outerHeight();
			var hash = this.hash;
			$("html, body").animate(
				{
					scrollTop: $(hash).offset().top - offset,
				},
				800,
				function () {
					// window.location.hash = hash;
				}
			);
		} // End if
	});

	$("section").each(function () {
		const $section = $(this);
		const $items = $section.find(".tab-item");

		$items.hide(); // hide all first
		const $active = $items.filter(".active");

		if ($active.length) {
			$active.show(); // show only active one
		} else {
			// fallback: show first tab if none marked active
			$items.first().show().addClass("active");
			$section
				.find(".tab-nav li:first")
				.addClass("active")
				.siblings()
				.removeClass("active");
		}
	});
	$(".tab-nav a").on("click", function (e) {
		e.preventDefault();

		const $nav = $(this).parents(".tab-nav");
		const $section = $(this).parents("section");

		// Update active nav link
		$nav.find("li").removeClass("active");
		$(this).parents("li").addClass("active");

		const tab = $(this).attr("data-type");
		const $items = $section.find(".tab-item");

		// Hide all tabs
		$items.hide().removeClass("active");

		// Fade in selected tab
		$section.find("#" + tab).fadeIn(300).addClass("active");
	});


	$(".view-more-wrap").each(function () {
		const $wrapper = $(this);
		const initialShow = parseInt($wrapper.data('initial-show') || 4);
		const incrementBy = parseInt($wrapper.data('increment') || 6);

		let currentVisible = initialShow;
		const totalItems = $wrapper.find(".item").length;

		// Show initial items (but don't show more than what exists)
		$wrapper
			.find(".item")
			.slice(0, Math.min(currentVisible, totalItems))
			.show(function () {
				$(this).css("display", "flex");
			});

		// Hide view more button if total items <= initial show amount
		if (totalItems <= initialShow) {
			$wrapper.addClass("disable-btn");
			return; // Exit early since no "view more" functionality is needed
		}

		// Attach click handler to this specific instance
		$wrapper
			.find(".btn-primary")
			.on("click", function (e) {
				e.preventDefault();

				currentVisible += incrementBy;

				$wrapper
					.find(".item")
					.slice(0, currentVisible)
					.slideDown(function () {
						$(this).css("display", "flex");
					});

				// Hide button if all items are now visible
				if (currentVisible >= totalItems) {
					$wrapper.addClass("disable-btn");
				}
			});
	});


	//setBackground
	setBackground.forEach((attributes) => {
		attributes.style.cssText = `
		background-image: url(${attributes.getAttribute("setBackground")});
		background-size: cover;
		background-position: center;
	  `;
	});
	try {
		document.querySelectorAll('.wrap-form textarea').forEach(function (textarea) {
			textarea.value = textarea.value.trim();
		});
	} catch (error) {

	}

	if (counterItem !== null) {
		if (counterItem.length) {
			const counterUp = window.counterUp.default;
			const callback = (entries) => {
				entries.forEach((entry) => {
					const el = entry.target;
					if (
						entry.isIntersecting &&
						!el.classList.contains("is-visible")
					) {
						counterUp(el, {
							duration: 2000,
							delay: 200,
						});
						el.classList.add("is-visible");
					}
				});
			};
			const IO = new IntersectionObserver(callback, { threshold: 1 });

			counterItem.forEach((counter) => {
				IO.observe(counter);
			});
		}
	}


	const homeNav = document.querySelector(".home-nav");

	if (homeNav) {
		let ticking = false;

		const getOffset = () => {
			const rect = homeNav.getBoundingClientRect();
			return rect.top + window.scrollY + rect.height;
		};

		let OFFSET = getOffset();

		// Recalculate on resize (important for responsive layouts)
		window.addEventListener("resize", () => {
			OFFSET = getOffset();
		});

		window.addEventListener("scroll", () => {
			if (!ticking) {
				requestAnimationFrame(() => {
					document.body.classList.toggle(
						"is-active-nav",
						window.scrollY > OFFSET
					);
					ticking = false;
				});
				ticking = true;
			}
		});
	}


}
